#pragma once

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>

/**
 * Launches the GQA Paged Prefill Causal Attention kernel.
 * 
 * @param q Query tensor [total_q, num_qo_heads, head_dim] (BF16)
 * @param k_cache KV Cache [num_pages, page_size, num_kv_heads, head_dim] (BF16)
 * @param v_cache KV Cache [num_pages, page_size, num_kv_heads, head_dim] (BF16)
 * @param qo_indptr Query offsets [len_indptr] (INT32)
 * @param kv_indptr KV offsets [len_indptr] (INT32)
 * @param kv_indices KV Page IDs [num_kv_indices] (INT32)
 * @param sm_scale Scaling factor for attention logits
 * @param output Output tensor [total_q, num_qo_heads, head_dim] (BF16)
 * @param lse Log-Sum-Exp tensor [total_q, num_qo_heads] (FLOAT32)
 */
void launch_gqa_paged_prefill(
    const at::Tensor& q,
    const at::Tensor& k_cache,
    const at::Tensor& v_cache,
    const at::Tensor& qo_indptr,
    const at::Tensor& kv_indptr,
    const at::Tensor& kv_indices,
    const float sm_scale,
    at::Tensor& output,
    at::Tensor& lse
);

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <math_constants.h>
#include <limits>
#include <algorithm>
#include <stdexcept>
#include <torch/extension.h>
#include "kernel.h"

// Constants from specification
constexpr int NUM_QO_HEADS = 32;
constexpr int NUM_KV_HEADS = 4;
constexpr int HEAD_DIM = 128;
constexpr int PAGE_SIZE = 1;
constexpr int BLOCK_SIZE = 256;
constexpr int THREADS_PER_HEAD = BLOCK_SIZE / NUM_QO_HEADS;  // 8 threads per head
constexpr int GQA_RATIO = NUM_QO_HEADS / NUM_KV_HEADS;       // 8

// Helper function for binary search to find sequence ID
__device__ __forceinline__ int find_seq_id(int global_q_idx, const int* qo_indptr, int len_indptr) {
    int low = 0;
    int high = len_indptr - 2;
    while (low < high) {
        int mid = low + (high - low + 1) / 2;
        if (qo_indptr[mid] <= global_q_idx) {
            low = mid;
        } else {
            high = mid - 1;
        }
    }
    return low;
}

__global__ void gqa_paged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int* __restrict__ qo_indptr,
    const int* __restrict__ kv_indptr,
    const int* __restrict__ kv_indices,
    float sm_scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int total_q,
    int len_indptr
) {
    int global_q_idx = blockIdx.x;
    if (global_q_idx >= total_q) return;

    int tid = threadIdx.x;
    int head_id = tid / THREADS_PER_HEAD;
    int dim_id = tid % THREADS_PER_HEAD;

    // Find sequence ID using binary search
    int seq_id = find_seq_id(global_q_idx, qo_indptr, len_indptr);

    // Sequence bounds
    int q_start = qo_indptr[seq_id];
    int q_end = qo_indptr[seq_id + 1];
    int local_q_idx = global_q_idx - q_start;
    int num_q_tokens = q_end - q_start;

    int kv_start = kv_indptr[seq_id];
    int kv_end = kv_indptr[seq_id + 1];
    int num_kv_tokens = kv_end - kv_start;

    // Causal mask calculation
    int delta = num_kv_tokens - num_q_tokens;
    int max_kv_idx = min(local_q_idx + 1 + delta, num_kv_tokens);

    if (max_kv_idx <= 0) {
        // No valid attention, set output to zero and LSE to -inf
        int out_offset = global_q_idx * NUM_QO_HEADS * HEAD_DIM + head_id * HEAD_DIM;
        for (int d = dim_id; d < HEAD_DIM; d += THREADS_PER_HEAD) {
            output[out_offset + d] = __float2bfloat16(0.0f);
        }
        if (dim_id == 0) {
            lse[global_q_idx * NUM_QO_HEADS + head_id] = -INFINITY;
        }
        return;
    }

    // Initialize state for online softmax
    float head_max = -INFINITY;
    float head_sum = 0.0f;
    __shared__ float head_out_shmem[NUM_QO_HEADS][HEAD_DIM];

    // Initialize output to 0
    for (int d = dim_id; d < HEAD_DIM; d += THREADS_PER_HEAD) {
        head_out_shmem[head_id][d] = 0.0f;
    }
    __syncthreads();

    // Load Q token for this head
    __nv_bfloat16 q_head[HEAD_DIM];
    int q_stride = NUM_QO_HEADS * HEAD_DIM;
    int q_base_offset = global_q_idx * q_stride + head_id * HEAD_DIM;

    // Load Q in chunks
    for (int d = dim_id; d < HEAD_DIM; d += THREADS_PER_HEAD) {
        q_head[d] = q[q_base_offset + d];
    }
    __syncthreads();

    // Shared memory for K and V (for one page)
    extern __shared__ __nv_bfloat16 smem[];
    __nv_bfloat16* s_k = smem;
    __nv_bfloat16* s_v = smem + NUM_KV_HEADS * HEAD_DIM;

    // Loop over KV tokens
    for (int k_idx = 0; k_idx < max_kv_idx; ++k_idx) {
        // Get page ID
        int page_id = kv_indices[kv_start + k_idx];

        // Load K and V into shared memory
        int kv_stride = NUM_KV_HEADS * HEAD_DIM;
        int kv_base = page_id * kv_stride;

        // Each thread loads elements for all KV heads
        int total_kv_elements = NUM_KV_HEADS * HEAD_DIM;
        for (int idx = tid; idx < total_kv_elements; idx += BLOCK_SIZE) {
            s_k[idx] = k_cache[kv_base + idx];
            s_v[idx] = v_cache[kv_base + idx];
        }
        __syncthreads();

        // Compute dot product for this head
        int kv_head = head_id / GQA_RATIO;

        // Load K row for this KV head and compute dot product
        float dot_acc = 0.0f;
        for (int d = dim_id; d < HEAD_DIM; d += THREADS_PER_HEAD) {
            __nv_bfloat16 k_val = s_k[kv_head * HEAD_DIM + d];
            float q_val = __bfloat162float(q_head[d]);
            float k_f = __bfloat162float(k_val);
            dot_acc += q_val * k_f;
        }

        // Reduce dot product across threads in the head group using warp shuffle
        float dot_val = dot_acc;
        int lane = tid % THREADS_PER_HEAD;  // 0..7

        // Manual reduction for 8 threads using warp shuffle
        #pragma unroll
        for (int offset = 4; offset > 0; offset /= 2) {
            float val = __shfl_down_sync(0xFFFFFFFF, dot_val, offset);
            dot_val += val;
        }

        // Thread 0 of the group updates state
        if (lane == 0) {
            float logits = dot_val * sm_scale;

            // Online Softmax Update
            if (logits > head_max) {
                float scale = __expf(head_max - logits);
                head_sum = head_sum * scale + 1.0f;
                for (int d = 0; d < HEAD_DIM; d++) {
                    head_out_shmem[head_id][d] = head_out_shmem[head_id][d] * scale;
                }
                head_max = logits;
            } else {
                float scale = __expf(logits - head_max);
                head_sum = head_sum + scale;
                for (int d = 0; d < HEAD_DIM; d++) {
                    float v_val = __bfloat162float(s_v[kv_head * HEAD_DIM + d]);
                    head_out_shmem[head_id][d] = head_out_shmem[head_id][d] + v_val * scale;
                }
            }
        }
        __syncthreads();
    }

    // Finalize Output and LSE
    int lane = tid % THREADS_PER_HEAD;
    if (lane == 0) {
        float final_lse = -INFINITY;
        if (head_sum > 0.0f) {
            final_lse = head_max + __logf(head_sum);
            float inv_sum = 1.0f / head_sum;
            for (int d = 0; d < HEAD_DIM; d++) {
                head_out_shmem[head_id][d] = head_out_shmem[head_id][d] * inv_sum;
            }
            // Convert LSE to base 2
            final_lse = final_lse / __logf(2.0f);
        } else {
            // No valid attention
            for (int d = 0; d < HEAD_DIM; d++) {
                head_out_shmem[head_id][d] = 0.0f;
            }
        }

        // Store Output
        int out_offset = global_q_idx * NUM_QO_HEADS * HEAD_DIM + head_id * HEAD_DIM;
        for (int d = 0; d < HEAD_DIM; d++) {
            output[out_offset + d] = __float2bfloat16(head_out_shmem[head_id][d]);
        }

        // Store LSE
        lse[global_q_idx * NUM_QO_HEADS + head_id] = final_lse;
    }
}

void launch_gqa_paged_prefill(
    const at::Tensor& q,
    const at::Tensor& k_cache,
    const at::Tensor& v_cache,
    const at::Tensor& qo_indptr,
    const at::Tensor& kv_indptr,
    const at::Tensor& kv_indices,
    const float sm_scale,
    at::Tensor& output,
    at::Tensor& lse
) {
    int total_q = q.size(0);
    int len_indptr = qo_indptr.size(0);

    if (total_q == 0) return;

    // Shared memory size: 2 * NUM_KV_HEADS * HEAD_DIM * sizeof(__nv_bfloat16)
    size_t shared_mem_size = 2 * NUM_KV_HEADS * HEAD_DIM * sizeof(__nv_bfloat16);

    dim3 grid(total_q);
    dim3 block(BLOCK_SIZE);

    gqa_paged_prefill_kernel<<<grid, block, shared_mem_size>>>(
        q.data_ptr<__nv_bfloat16>(),
        k_cache.data_ptr<__nv_bfloat16>(),
        v_cache.data_ptr<__nv_bfloat16>(),
        qo_indptr.data_ptr<int>(),
        kv_indptr.data_ptr<int>(),
        kv_indices.data_ptr<int>(),
        sm_scale,
        output.data_ptr<__nv_bfloat16>(),
        lse.data_ptr<float>(),
        total_q,
        len_indptr
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include "kernel.h"
#include <vector>
#include <stdexcept>
#include <string>
#include <cuda_bf16.h>
#include <cuda_runtime.h>

// Validation helper for BF16 tensors
void validate_tensor_bf16(const at::Tensor& tensor, const std::string& name) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.dtype() != torch::kBFloat16) {
        throw std::runtime_error(name + " must have dtype BFloat16, got " + c10::toString(tensor.dtype()));
    }
}

// Validation helper for INT32 tensors
void validate_tensor_int32(const at::Tensor& tensor, const std::string& name) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.dtype() != torch::kInt32) {
        throw std::runtime_error(name + " must have dtype INT32, got " + c10::toString(tensor.dtype()));
    }
}

// Main run function
std::vector<at::Tensor> run(
    const at::Tensor& q,
    const at::Tensor& k_cache,
    const at::Tensor& v_cache,
    const at::Tensor& qo_indptr,
    const at::Tensor& kv_indptr,
    const at::Tensor& kv_indices,
    float sm_scale
) {
    // Validate inputs
    validate_tensor_bf16(q, "q");
    validate_tensor_bf16(k_cache, "k_cache");
    validate_tensor_bf16(v_cache, "v_cache");
    validate_tensor_int32(qo_indptr, "qo_indptr");
    validate_tensor_int32(kv_indptr, "kv_indptr");
    validate_tensor_int32(kv_indices, "kv_indices");

    // Check shapes
    int total_q = q.size(0);
    int num_qo_heads = q.size(1);
    int head_dim = q.size(2);

    int num_pages = k_cache.size(0);
    int page_size = k_cache.size(1);
    int num_kv_heads = k_cache.size(2);
    int k_head_dim = k_cache.size(3);

    int len_indptr = qo_indptr.size(0);
    int num_kv_indices = kv_indices.size(0);

    // Verify constants
    if (num_qo_heads != 32) {
        throw std::runtime_error("num_qo_heads must be 32, got " + std::to_string(num_qo_heads));
    }
    if (num_kv_heads != 4) {
        throw std::runtime_error("num_kv_heads must be 4, got " + std::to_string(num_kv_heads));
    }
    if (head_dim != 128) {
        throw std::runtime_error("head_dim must be 128, got " + std::to_string(head_dim));
    }
    if (page_size != 1) {
        throw std::runtime_error("page_size must be 1, got " + std::to_string(page_size));
    }
    if (k_head_dim != 128) {
        throw std::runtime_error("k_cache head_dim must be 128, got " + std::to_string(k_head_dim));
    }

    // Verify constraints
    if (len_indptr == 0) {
        throw std::runtime_error("qo_indptr cannot be empty");
    }
    if (total_q != qo_indptr[-1].item<int>()) {
        throw std::runtime_error("total_q must match qo_indptr[-1]");
    }
    if (num_kv_indices != kv_indptr[-1].item<int>()) {
        throw std::runtime_error("num_kv_indices must match kv_indptr[-1]");
    }

    // Allocate outputs
    at::Tensor output = at::empty({total_q, num_qo_heads, head_dim}, torch::kBFloat16).cuda();
    at::Tensor lse = at::full({total_q, num_qo_heads}, -INFINITY, torch::kFloat32).cuda();

    // Launch kernel
    launch_gqa_paged_prefill(
        q, k_cache, v_cache, qo_indptr, kv_indptr, kv_indices, sm_scale, output, lse
    );

    // Synchronize to ensure completion
    cudaDeviceSynchronize();

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Execute GQA Paged Prefill Causal Attention");
}
